SELECT status, AVG(run_duration) AS avg_run_duration
FROM algorithm_runs
WHERE status = 'running';

SELECT run_id, run_duration
FROM algorithm_runs
WHERE run_duration = (SELECT MAX(run_duration) FROM algorithm_runs);

SELECT COUNT(*) as total_successful_runs
FROM algorithm_runs
WHERE status = 'completed';

SELECT COUNT(*) 
FROM run_tag_map 
WHERE tag_id = (SELECT tag_id FROM run_tags WHERE tag_name = 'baseline');

SELECT tag_name
FROM run_tags
WHERE tag_id = 1;
